\$content = Get-Content app/actions.ts -Raw
\$content = \$content -replace 'try \{\s*const \{ error \} = await supabaseAdmin\s*\.from\(''complaints''\)\s*\.insert\(\{.*?\}\);\s*if \(error\) throw error;\s*return \{ success: true \};\s*\}', \"try \{\r\n    if (USE_LOCAL_DB && sql) \{\r\n      await sql\\r\n        INSERT INTO complaints (description, channel, evidence_image_url, status, created_at)\r\n        VALUES (\\, \\, \\, ''PENDING'', NOW())\r\n      \;\r\n    \} else \{\r\n      const \{ error \} = await supabaseAdmin.from(''complaints'').insert(\{\r\n        description: formData.description,\r\n        channel: formData.channel,\r\n        evidence_image_url: formData.evidence_image_url,\r\n        status: ''PENDING'',\r\n        created_at: new Date().toISOString()\r\n      \});\r\n      if (error) throw error;\r\n    \}\r\n    return \{ success: true \};\r\n  \}\"
Set-Content -Path app/actions.ts -Value \$content -Encoding UTF8
